import React, { useEffect, useState } from 'react';
import { useSelector } from 'react-redux';
import { useFormik } from 'formik';
import { toast } from 'react-toastify';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';
import { fdSchema, rdSchema } from '../../schemas';

export default function InvestmentsPage() {
  const { accounts } = useSelector(s => s.accounts);
  const [fds, setFds] = useState([]);
  const [rds, setRds] = useState([]);
  const [activeTab, setActiveTab] = useState('fd');
  const [loading, setLoading] = useState(false);

  const activeAccount = accounts.find(a => a.status === 'ACTIVE');

  const fetchData = async () => {
    try {
      const [fdRes, rdRes] = await Promise.all([
        axiosInstance.get('/investments/fd/my'),
        axiosInstance.get('/investments/rd/my')
      ]);
      setFds(fdRes.data.fds || []);
      setRds(rdRes.data.rds || []);
    } catch {}
  };

  useEffect(() => { fetchData(); }, []);

  const fdFormik = useFormik({
    initialValues: { amount: '', interestRate: '7', tenureMonths: '12' },
    validationSchema: fdSchema,
    onSubmit: async (values, { resetForm }) => {
      setLoading(true);
      try {
        await axiosInstance.post('/investments/fd', { ...values, accountNumber: activeAccount?.accountNumber });
        toast.success('Fixed Deposit created!');
        fetchData(); resetForm();
      } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
      finally { setLoading(false); }
    }
  });

  const rdFormik = useFormik({
    initialValues: { monthlyAmount: '', interestRate: '6', tenureMonths: '12' },
    validationSchema: rdSchema,
    onSubmit: async (values, { resetForm }) => {
      setLoading(true);
      try {
        await axiosInstance.post('/investments/rd', { ...values, accountNumber: activeAccount?.accountNumber });
        toast.success('Recurring Deposit created!');
        fetchData(); resetForm();
      } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
      finally { setLoading(false); }
    }
  });

  const payRDInstallment = async (rdId) => {
    try {
      await axiosInstance.post(`/investments/rd/${rdId}/pay`);
      toast.success('Installment paid!');
      fetchData();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const inp = { padding: '10px 14px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, width: '100%', boxSizing: 'border-box', marginBottom: 12 };
  const tabStyle = (active) => ({ padding: '10px 24px', border: 'none', borderRadius: 8, cursor: 'pointer', fontWeight: 600, background: active ? '#3b82f6' : '#fff', color: active ? '#fff' : '#64748b' });
  const statusColor = { ACTIVE: '#22c55e', MATURED: '#3b82f6', BROKEN: '#ef4444' };

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 style={{ margin: '0 0 24px', color: '#1e293b' }}> Investments</h2>
      </div>

      <div className="d-flex flex-wrap gap-2 mb-4">
        {['fd', 'rd'].map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab)} style={tabStyle(activeTab === tab)}>
            {tab === 'fd' ? ' Fixed Deposits' : ' Recurring Deposits'}
          </button>
        ))}
      </div>

      <div className="row g-4 align-items-start">
        {/* Create form */}
        <div className="col-12 col-md-6 col-lg-5">
          <div style={{ background: '#fff', borderRadius: 12, padding: 24, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
            <h3 style={{ margin: '0 0 20px' }}>{activeTab === 'fd' ? 'Open Fixed Deposit' : 'Start Recurring Deposit'}</h3>
            {!activeAccount ? (
              <p style={{ color: '#ef4444', fontSize: 13 }}>No active account found. Please contact admin.</p>
            ) : activeTab === 'fd' ? (
              <form onSubmit={fdFormik.handleSubmit}>
                {[['amount', 'Amount (₹)', 'Min ₹1,000'], ['interestRate', 'Interest Rate (%)', '7'], ['tenureMonths', 'Tenure (Months)', '12']].map(([name, lbl, ph]) => (
                  <div key={name}>
                    <label style={{ fontSize: 13, fontWeight: 600 }}>{lbl}</label>
                    <input type="number" style={inp} placeholder={ph} {...fdFormik.getFieldProps(name)} />
                    {fdFormik.touched[name] && fdFormik.errors[name] && <div style={{ color: '#ef4444', fontSize: 12, marginTop: -8, marginBottom: 8 }}>{fdFormik.errors[name]}</div>}
                  </div>
                ))}
                {fdFormik.values.amount && fdFormik.values.interestRate && fdFormik.values.tenureMonths && (
                  <div style={{ background: '#f0fdf4', borderRadius: 8, padding: 12, marginBottom: 16, border: '1px solid #bbf7d0', fontSize: 13 }}>
                    Maturity Amount: <strong>₹{Math.round(Number(fdFormik.values.amount) * (1 + (fdFormik.values.interestRate / 100) * (fdFormik.values.tenureMonths / 12))).toLocaleString('en-IN')}</strong>
                  </div>
                )}
                <button type="submit" disabled={loading} style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>
                  {loading ? 'Creating...' : 'Create FD'}
                </button>
              </form>
            ) : (
              <form onSubmit={rdFormik.handleSubmit}>
                {[['monthlyAmount', 'Monthly Amount (₹)', 'Min ₹100'], ['interestRate', 'Interest Rate (%)', '6'], ['tenureMonths', 'Tenure (Months)', '12']].map(([name, lbl, ph]) => (
                  <div key={name}>
                    <label style={{ fontSize: 13, fontWeight: 600 }}>{lbl}</label>
                    <input type="number" style={inp} placeholder={ph} {...rdFormik.getFieldProps(name)} />
                    {rdFormik.touched[name] && rdFormik.errors[name] && <div style={{ color: '#ef4444', fontSize: 12, marginTop: -8, marginBottom: 8 }}>{rdFormik.errors[name]}</div>}
                  </div>
                ))}
                <button type="submit" disabled={loading} style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>
                  {loading ? 'Creating...' : 'Start RD'}
                </button>
              </form>
            )}
          </div>
        </div>

        {/* FD / RD list */}
        <div className="col-12 col-md-6 col-lg-7">
          {activeTab === 'fd' ? (
            fds.length === 0 ? (
              <div style={{ background: '#fff', borderRadius: 12, padding: 32, textAlign: 'center', color: '#94a3b8' }}>No Fixed Deposits yet</div>
            ) : fds.map(fd => (
              <div key={fd.fdId} style={{ background: '#fff', borderRadius: 12, padding: 20, marginBottom: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
                <div className="d-flex justify-content-between flex-wrap gap-2 mb-3">
                  <span style={{ fontFamily: 'monospace', fontSize: 13, color: '#64748b' }}>{fd.fdId}</span>
                  <span style={{ fontSize: 12, fontWeight: 700, color: statusColor[fd.status] }}>{fd.status}</span>
                </div>
                <div className="row g-2" style={{ fontSize: 13 }}>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Amount</p><strong>₹{fd.amount?.toLocaleString('en-IN')}</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Maturity Amount</p><strong>₹{fd.maturityAmount?.toLocaleString('en-IN')}</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Rate</p><strong>{fd.interestRate}%</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Tenure</p><strong>{fd.tenureMonths} months</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Start</p><strong>{new Date(fd.startDate).toLocaleDateString('en-IN')}</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Maturity</p><strong>{new Date(fd.maturityDate).toLocaleDateString('en-IN')}</strong></div>
                </div>
              </div>
            ))
          ) : (
            rds.length === 0 ? (
              <div style={{ background: '#fff', borderRadius: 12, padding: 32, textAlign: 'center', color: '#94a3b8' }}>No Recurring Deposits yet</div>
            ) : rds.map(rd => (
              <div key={rd.rdId} style={{ background: '#fff', borderRadius: 12, padding: 20, marginBottom: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
                <div className="d-flex justify-content-between flex-wrap gap-2 mb-3">
                  <span style={{ fontFamily: 'monospace', fontSize: 13, color: '#64748b' }}>{rd.rdId}</span>
                  <span style={{ fontSize: 12, fontWeight: 700, color: statusColor[rd.status] }}>{rd.status}</span>
                </div>
                <div className="row g-2" style={{ fontSize: 13, marginBottom: 12 }}>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Monthly</p><strong>₹{rd.monthlyAmount?.toLocaleString('en-IN')}</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Tenure</p><strong>{rd.tenureMonths} months</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Paid</p><strong>{rd.paidInstallments} / {rd.tenureMonths}</strong></div>
                  <div className="col-6"><p style={{ margin: 0, color: '#94a3b8', fontSize: 12 }}>Rate</p><strong>{rd.interestRate}%</strong></div>
                </div>
                <div style={{ background: '#e2e8f0', borderRadius: 99, height: 8, marginBottom: 12 }}>
                  <div style={{ background: '#3b82f6', borderRadius: 99, height: 8, width: `${(rd.paidInstallments / rd.tenureMonths) * 100}%` }} />
                </div>
                {rd.status === 'ACTIVE' && rd.paidInstallments < rd.tenureMonths && (
                  <button onClick={() => payRDInstallment(rd.rdId)} style={{ padding: '8px 16px', borderRadius: 8, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700, cursor: 'pointer', fontSize: 13 }}>
                    Pay Installment ₹{rd.monthlyAmount?.toLocaleString('en-IN')}
                  </button>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </Layout>
  );
}
